create table inpatient_data
(
    inpatient_sk integer,
    drg_code     integer,
    hospital_id  numeric,
    amount_code  varchar(5),
    amount       numeric
);




create table hospital
(
    hospital_id          numeric,
    hospital_name        varchar(255),
    hospital_address     varchar(255),
    hospital_city        varchar(255),
    hospital_state       varchar(255),
    hospital_postal_code varchar(255),
    region_id            integer
);




create table type_code
(
    type_code        varchar(5),
    type_description varchar(50)
);


create table hospital_report
(
    hospital_id       numeric,
    hospital_name     text,
    city              text,
    state             text,
    discharges        numeric,
    charges           numeric,
    total_payments    numeric,
    medicare_payments numeric
);

